+        match ch {
+            '"' | '\'' => {
+                let quote = ch;
+                out.push(' ');
+                let mut escaped = false;
+                for c in chars.by_ref() {
+                    out.push(' ');
+                    if escaped {
+                        escaped = false;
+                        continue;
+                    }
+                    if c == '\\' {
+                        escaped = true;
+                        continue;
+                    }
+                    if c == quote {
+                        break;
+                    }
+                }
+            }
+            '{' => {
+                out.push(' ');
+                let mut depth = 1usize;
+                let mut in_string: Option<char> = None;
+                let mut escaped = false;
+
+                for c in chars.by_ref() {
+                    out.push(' ');
+                    if let Some(quote) = in_string {
+                        if escaped {
+                            escaped = false;
+                            continue;
+                        }
+                        if c == '\\' {
+                            escaped = true;
+                            continue;
+                        }
+                        if c == quote {
+                            in_string = None;
+                        }
+                        continue;
+                    }
+
+                    match c {
+                        '"' | '\'' | '`' => {
+                            in_string = Some(c);
+                        }
+                        '{' => {
+                            depth += 1;
+                        }
+                        '}' => {
+                            depth -= 1;
+                            if depth == 0 {
+                                break;
+                            }
+                        }
+                        _ => {}
+                    }
+                }
+            }
+            _ => out.push(ch),
+        }
+    }
+
+    out
